query:
SELECT productLane, COUNT(*) as cnt FROM projects WHERE productLane IS NOT NULL GROUP BY productLane ORDER BY cnt DESC;
SELECT productLane, priority, COUNT(*) as cnt FROM projects WHERE productLane = 'pumps' GROUP BY productLane, priority;
SELECT COUNT(*) as total_pump_projects FROM projects WHERE productLane = 'pumps';
SELECT COUNT(*) as pump_contacts FROM contacts c JOIN contactProjects cp ON c.id = cp.contactId JOIN projects p ON cp.projectId = p.id WHERE p.productLane = 'pumps';

